const tagBadges=document.querySelectorAll(".tag-badge");tagBadges.forEach(e=>{e.addEventListener("click",function(t){t.preventDefault();const n=e.textContent.trim().toLowerCase().replace(/\s+/g,"-");filterPosts(n)})});function filterPosts(e){const t=document.querySelectorAll(".portfolio-item");t.forEach(t=>{if(e==="all"){t.style.display="block";return}t.classList.contains("tag-"+e)?t.style.display="block":t.style.display="none"})}